import React, { useState, useContext, useMemo } from "react";
import axios from "axios";
import GeneralContext from "./GeneralContext";
import "./BuyActionWindow.css";

const API_URL = process.env.REACT_APP_API_URL || "http://localhost:3002";

const BuyActionWindow = ({ uid, currentPrice }) => {
  const { closeBuyWindow, refreshDashboard } = useContext(GeneralContext);

  const [stockQuantity, setStockQuantity] = useState(1);
  const [stockPrice, setStockPrice] = useState(currentPrice || 0);
  const [loading, setLoading] = useState(false);

  // 🔥 Calculate margin dynamically
  const totalAmount = useMemo(() => {
    return stockQuantity * stockPrice;
  }, [stockQuantity, stockPrice]);

  const handleBuyClick = async () => {
    if (!uid) return;

    if (stockQuantity <= 0 || stockPrice <= 0) {
      alert("Quantity and price must be greater than 0");
      return;
    }

    try {
      setLoading(true);

      await axios.post(`${API_URL}/newOrder`, {
        name: uid,
        qty: Number(stockQuantity),
        price: Number(stockPrice),
        mode: "BUY",
      });

      // 🔥 Trigger refresh of holdings
      if (refreshDashboard) refreshDashboard();

      closeBuyWindow();
    } catch (error) {
      console.error("Order failed:", error.response?.data || error.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="container" id="buy-window">
      <div className="regular-order">
        <h3 style={{ marginBottom: "20px" }}>Buy {uid}</h3>

        <div className="inputs">
          <fieldset>
            <legend>Qty.</legend>
            <input
              type="number"
              min="1"
              value={stockQuantity}
              onChange={(e) => setStockQuantity(Number(e.target.value))}
            />
          </fieldset>

          <fieldset>
            <legend>Price</legend>
            <input
              type="number"
              step="0.05"
              min="0.05"
              value={stockPrice}
              onChange={(e) => setStockPrice(Number(e.target.value))}
            />
          </fieldset>
        </div>

        {/* 🔥 Dynamic Calculation */}
        <div style={{ marginTop: "15px", fontWeight: "500" }}>
          Total: ₹{totalAmount.toLocaleString("en-IN")}
        </div>
      </div>

      <div className="buttons">
        <span>Required: ₹{totalAmount.toLocaleString("en-IN")}</span>

        <div>
          <button
            className="btn btn-blue"
            onClick={handleBuyClick}
            disabled={loading}
          >
            {loading ? "Processing..." : "Buy"}
          </button>

          <button
            className="btn btn-grey"
            onClick={closeBuyWindow}
            disabled={loading}
          >
            Cancel
          </button>
        </div>
      </div>
    </div>
  );
};

export default BuyActionWindow;
